ggplot(recommendations, aes(x = Min_Tasks, y = Min_Raters, color = Target_Phi, label = Purpose)) +
  geom_point(size = 4) +
  geom_text(vjust = -0.8, size = 3.2, check_overlap = TRUE) +
  scale_color_viridis_c(name = "Target Phi") +
  scale_x_continuous(breaks = sort(unique(recommendations$Min_Tasks))) +
  scale_y_continuous(breaks = sort(unique(recommendations$Min_Raters))) +
  labs(
    title = "Recommended Designs by Purpose (Minimum Requirements)",
    x = "Minimum tasks", y = "Minimum raters"
  ) +
  theme_bw(base_size = 12) + theme(legend.position = "bottom")
```

